#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, P, K;
        scanf("%d %d %d %d", &N, &M, &P, &K);
        double prob = 0.0;
        // Calculate the probability of winning at least P games
        for (int i = P; i <= K; i++) {
            double binom_prob = 1.0;
            for (int j = 0; j < i; j++) {
                binom_prob *= (K - j) / (i - j);
            }
            for (int j = 0; j < K - i; j++) {
                binom_prob *= (K - i - j) / (K - i - j);
            }
            binom_prob *= pow(0.5, K);
            prob += binom_prob;
        }
        printf("%.6f\n", prob);
    }
    return 0;
}

