            int K = sc.nextInt();
            double prob = 0.0;
            // Calculate the probability of winning at least P games
            for (int i = P; i <= K; i++) {
                double binom_prob = 1.0;
                for (int j = 0; j < i; j++) {
                    binom_prob *= (K - j) / (double) (i - j);
                }
                for (int j = 0; j < K - i; j++) {
                    binom_prob *= (K - i - j) / (double) (K - i - j);
                }
                binom_prob *= Math.pow(0.5, K);
                prob += binom_prob;
            }
            System.out.printf("%.6f\n", prob);
        }
    }
